class Lbl(StrEnum):
    SRC = ' (source)'
    RNG = ' (range)'

# %% ../../nbs/api/pymor/vectorarrays.ipynb
def _unlabel_dims(obj):
    match obj:
        case str(): return obj.removesuffix(Lbl.SRC).removesuffix(Lbl.RNG)
        case tuple(): return tuple(_unlabel_dims(dim) for dim in obj)
        case list(): return [_unlabel_dims(dim) for dim in obj]
        case dict(): return {_unlabel_dims(k): _unlabel_dims(v) for k,v in obj.items()}
        case Coordinates(): return Coordinates({_unlabel_dims(k): v.data for k,v in obj.items()})
        case DataArray(): return obj.rename({dim: _unlabel_dims(dim) for dim in obj.dims})
        case XarrayVectorSpace(): return obj.with_(coords_data=[(_unlabel_dims(dim), data, attrs) for dim,data,attrs in obj.coords_data])
    return obj

