def transpose_like(a:ndarray, dims, new_dims):
    return a.transpose([dims.index(d) for d in new_dims])

# %% ../../nbs/api/pymor/vectorarrays.ipynb
def parse_coords(coords:Coordinates|dict|list|tuple|None):
    match coords:
        case Coordinates():
            return [(k, v.data, v.attrs) for k,v in coords.items()]
        case dict():
            return [(k, v, {}) for k,v in coords.items()]
        case list() | tuple():
            return coords
        case None:
            return []   

