@patch
def from_numpy(
    self:XarrayVectorSpace, 
    data:ndarray, 
    extended_coords_data:dict|str|None=None, 
    id=None, 
    ensure_copy=False
)->XarrayVectorArray: # A vector array with data from the numpy array
    """Return an `XarrayVectorArray` in the vector space with data from the `ndarray` `data`."""
    if ensure_copy: data = data.copy()
    if extended_coords_data is None:
        extended_coords_data = {}
    elif isinstance(extended_coords_data, str):
        extended_coords_data = {extended_coords_data: np.arange(data.size // self.dim)}
    extended_shape = [len(v) for v in extended_coords_data.values()]
    shape = extended_shape + self.shape
    return self.from_data(data.reshape(shape), list(extended_coords_data) + self.dims, extended_coords_data)

